public class DefaultMethods {
    interface Greeter {
        String greet(String name);
        default String greetLoud(String name) { return greet(name).toUpperCase(); }
        static Greeter formal() { return name -> "Dear " + name; }
    }
    public static void main(String[] args) {
        Greeter g = name -> "Hi " + name;
        System.out.println(g.greet("Alice"));
        System.out.println(g.greetLoud("Bob"));
        System.out.println(Greeter.formal().greet("Carol"));
    }
}
